unit lipdecide;

{$mode objfpc}
{$H+}

interface

const
  PI = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : NPOINTS;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : NPOINTS;
    QUADS    : NUMQUADS;
    DIST     : real;
    N_PTS    : NPTYPE;
    K_PTS    : POINTRANGE;
    A_PTS    : POINTRANGE;
    B_PTS    : POINTRANGE;
    C_PTS    : POINTRANGE;
    D_PTS    : POINTRANGE;
    E_PTS    : POINTRANGE;
    F_PTS    : POINTRANGE;
    G_PTS    : POINTRANGE;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

function REALCOMPARE(A, B : real) : COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

{$I realcompare_reference.pas}

function PointsCoincide(I, J: integer): boolean;
begin
  PointsCoincide :=
    (REALCOMPARE(X[I], X[J]) = EQ) and (REALCOMPARE(Y[I], Y[J]) = EQ);
end;

function Distance(I, J: integer): real;
var
  dx, dy: real;
begin
  dx := X[I] - X[J];
  dy := Y[I] - Y[J];
  Distance := Sqrt(dx * dx + dy * dy);
end;

function TriangleArea(I, J, K: integer): real;
var
  ax, ay, bx, by: real;
begin
  ax := X[J] - X[I];
  ay := Y[J] - Y[I];
  bx := X[K] - X[I];
  by := Y[K] - Y[I];
  TriangleArea := Abs(ax * by - ay * bx) / 2.0;
end;

function AngleDefinedAndOutOfRange(I, J, K: integer; Eps: real): boolean;
var
  ux, uy, vx, vy, dotv, mu, mv, cosv, ang: real;
  piMinus, piPlus: real;
begin
  if PointsCoincide(I, J) or PointsCoincide(K, J) then
  begin
    AngleDefinedAndOutOfRange := false;
    Exit;
  end;

  ux := X[I] - X[J];
  uy := Y[I] - Y[J];
  vx := X[K] - X[J];
  vy := Y[K] - Y[J];
  dotv := ux * vx + uy * vy;
  mu := Sqrt(ux * ux + uy * uy);
  mv := Sqrt(vx * vx + vy * vy);

  cosv := dotv / (mu * mv);
  if REALCOMPARE(cosv, 1.0) = GT then
    cosv := 1.0
  else if REALCOMPARE(cosv, -1.0) = LT then
    cosv := -1.0;

  ang := ArcCos(cosv);
  piMinus := PI - Eps;
  piPlus := PI + Eps;

  AngleDefinedAndOutOfRange :=
    (REALCOMPARE(ang, piMinus) = LT) or (REALCOMPARE(ang, piPlus) = GT);
end;

function MinEnclosingRadius3(I, J, K: integer): real;
var
  a, b, c: real;
  a2, b2, c2: real;
  maxSide, max2, sum2: real;
  area: real;
  circum: real;
begin
  a := Distance(J, K);
  b := Distance(I, K);
  c := Distance(I, J);
  a2 := a * a;
  b2 := b * b;
  c2 := c * c;

  if (REALCOMPARE(a, b) <> LT) and (REALCOMPARE(a, c) <> LT) then
  begin
    maxSide := a;
    max2 := a2;
    sum2 := b2 + c2;
  end
  else if (REALCOMPARE(b, a) <> LT) and (REALCOMPARE(b, c) <> LT) then
  begin
    maxSide := b;
    max2 := b2;
    sum2 := a2 + c2;
  end
  else
  begin
    maxSide := c;
    max2 := c2;
    sum2 := a2 + b2;
  end;

  area := TriangleArea(I, J, K);
  if REALCOMPARE(area, 0.0) = EQ then
  begin
    MinEnclosingRadius3 := maxSide / 2.0;
    Exit;
  end;

  if (REALCOMPARE(max2, sum2) = GT) or (REALCOMPARE(max2, sum2) = EQ) then
  begin
    MinEnclosingRadius3 := maxSide / 2.0;
    Exit;
  end;

  circum := (a * b * c) / (4.0 * area);
  MinEnclosingRadius3 := circum;
end;

function DistancePointToLine(P, A, B: integer): real;
var
  ax, ay, bx, by, px, py: real;
  abx, aby, apx, apy: real;
  denom: real;
  num: real;
begin
  if PointsCoincide(A, B) then
  begin
    DistancePointToLine := Distance(P, A);
    Exit;
  end;

  ax := X[A];
  ay := Y[A];
  bx := X[B];
  by := Y[B];
  px := X[P];
  py := Y[P];

  abx := bx - ax;
  aby := by - ay;
  apx := px - ax;
  apy := py - ay;

  num := Abs(abx * apy - aby * apx);
  denom := Sqrt(abx * abx + aby * aby);
  DistancePointToLine := num / denom;
end;

function QuadrantOfPoint(I: integer): integer;
var
  xi, yi: real;
begin
  xi := X[I];
  yi := Y[I];

  if (REALCOMPARE(xi, 0.0) <> LT) and (REALCOMPARE(yi, 0.0) <> LT) then
    QuadrantOfPoint := 1
  else if (REALCOMPARE(xi, 0.0) <> GT) and (REALCOMPARE(yi, 0.0) <> LT) then
    QuadrantOfPoint := 2
  else if (REALCOMPARE(xi, 0.0) <> GT) and (REALCOMPARE(yi, 0.0) <> GT) then
    QuadrantOfPoint := 3
  else
    QuadrantOfPoint := 4;
end;

function LIC1Met: boolean;
var
  i: integer;
begin
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Distance(i, i + 1), PARAMETERS.LENGTH1) = GT then
    begin
      LIC1Met := true;
      Exit;
    end;
  LIC1Met := false;
end;

function LIC2Met: boolean;
var
  i: integer;
  r: real;
begin
  LIC2Met := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    r := MinEnclosingRadius3(i, i + 1, i + 2);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      LIC2Met := true;
      Exit;
    end;
  end;
end;

function LIC3Met: boolean;
var
  i: integer;
begin
  LIC3Met := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - 2 do
    if AngleDefinedAndOutOfRange(i, i + 1, i + 2, PARAMETERS.EPSILON) then
    begin
      LIC3Met := true;
      Exit;
    end;
end;

function LIC4Met: boolean;
var
  i: integer;
begin
  LIC4Met := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(i, i + 1, i + 2), PARAMETERS.AREA1) = GT then
    begin
      LIC4Met := true;
      Exit;
    end;
end;

function LIC5Met: boolean;
var
  startIdx, endIdx, i: integer;
  seen: array[1..4] of boolean;
  quad, count: integer;
begin
  LIC5Met := false;
  for startIdx := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for i := 1 to 4 do
      seen[i] := false;
    count := 0;
    endIdx := startIdx + PARAMETERS.Q_PTS - 1;
    for i := startIdx to endIdx do
    begin
      quad := QuadrantOfPoint(i);
      if not seen[quad] then
      begin
        seen[quad] := true;
        Inc(count);
      end;
    end;
    if count > PARAMETERS.QUADS then
    begin
      LIC5Met := true;
      Exit;
    end;
  end;
end;

function LIC6Met: boolean;
var
  i: integer;
begin
  LIC6Met := false;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i + 1] - X[i], 0.0) = LT then
    begin
      LIC6Met := true;
      Exit;
    end;
end;

function LIC7Met: boolean;
var
  startIdx, endIdx, i: integer;
  firstIdx, lastIdx: integer;
begin
  LIC7Met := false;
  if NUMPOINTS < 3 then
    Exit;

  for startIdx := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    firstIdx := startIdx;
    lastIdx := startIdx + PARAMETERS.N_PTS - 1;
    endIdx := lastIdx;
    for i := startIdx to endIdx do
      if REALCOMPARE(DistancePointToLine(i, firstIdx, lastIdx), PARAMETERS.DIST) = GT then
      begin
        LIC7Met := true;
        Exit;
      end;
  end;
end;

function LIC8Met: boolean;
var
  i, j: integer;
begin
  LIC8Met := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(Distance(i, j), PARAMETERS.LENGTH1) = GT then
    begin
      LIC8Met := true;
      Exit;
    end;
  end;
end;

function LIC9Met: boolean;
var
  i, j, k: integer;
  r: real;
  maxStart: integer;
begin
  LIC9Met := false;
  if NUMPOINTS < 5 then
    Exit;
  maxStart := NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := MinEnclosingRadius3(i, j, k);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      LIC9Met := true;
      Exit;
    end;
  end;
end;

function LIC10Met: boolean;
var
  i, j, k: integer;
  maxStart: integer;
begin
  LIC10Met := false;
  if NUMPOINTS < 5 then
    Exit;
  maxStart := NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    if AngleDefinedAndOutOfRange(i, j, k, PARAMETERS.EPSILON) then
    begin
      LIC10Met := true;
      Exit;
    end;
  end;
end;

function LIC11Met: boolean;
var
  i, j, k: integer;
  maxStart: integer;
begin
  LIC11Met := false;
  if NUMPOINTS < 5 then
    Exit;
  maxStart := NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    if REALCOMPARE(TriangleArea(i, j, k), PARAMETERS.AREA1) = GT then
    begin
      LIC11Met := true;
      Exit;
    end;
  end;
end;

function LIC12Met: boolean;
var
  i, j: integer;
begin
  LIC12Met := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0.0) = LT then
    begin
      LIC12Met := true;
      Exit;
    end;
  end;
end;

function LIC13Met: boolean;
var
  i, j: integer;
  d: real;
  hasGreater, hasLess: boolean;
begin
  LIC13Met := false;
  if NUMPOINTS < 3 then
    Exit;

  hasGreater := false;
  hasLess := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := Distance(i, j);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      hasGreater := true;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      hasLess := true;
  end;

  LIC13Met := hasGreater and hasLess;
end;

function LIC14Met: boolean;
var
  i, j, k: integer;
  r: real;
  hasNotInR1, hasInR2: boolean;
  maxStart: integer;
begin
  LIC14Met := false;
  if NUMPOINTS < 5 then
    Exit;

  hasNotInR1 := false;
  hasInR2 := false;
  maxStart := NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := MinEnclosingRadius3(i, j, k);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
      hasNotInR1 := true;
    if REALCOMPARE(r, PARAMETERS.RADIUS2) <> GT then
      hasInR2 := true;
  end;

  LIC14Met := hasNotInR1 and hasInR2;
end;

function LIC15Met: boolean;
var
  i, j, k: integer;
  a: real;
  hasGreater, hasLess: boolean;
  maxStart: integer;
begin
  LIC15Met := false;
  if NUMPOINTS < 5 then
    Exit;

  hasGreater := false;
  hasLess := false;
  maxStart := NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    a := TriangleArea(i, j, k);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then
      hasGreater := true;
    if REALCOMPARE(a, PARAMETERS.AREA2) = LT then
      hasLess := true;
  end;

  LIC15Met := hasGreater and hasLess;
end;

procedure DECIDE;
var
  i, j: integer;
  rowAll: boolean;
begin
  CMV[1] := LIC1Met;
  CMV[2] := LIC2Met;
  CMV[3] := LIC3Met;
  CMV[4] := LIC4Met;
  CMV[5] := LIC5Met;
  CMV[6] := LIC6Met;
  CMV[7] := LIC7Met;
  CMV[8] := LIC8Met;
  CMV[9] := LIC9Met;
  CMV[10] := LIC10Met;
  CMV[11] := LIC11Met;
  CMV[12] := LIC12Met;
  CMV[13] := LIC13Met;
  CMV[14] := LIC14Met;
  CMV[15] := LIC15Met;

  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;

  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      rowAll := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
          rowAll := false;
      FUV[i] := rowAll;
    end;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
      LAUNCH := false;
end;

end.
